# ----------------------------
# URL -> slug
# ----------------------------
def extract_slug(polymarket_url: str) -> str:
    path = urlparse(polymarket_url).path
    m = re.search(r"/(event|market)/([^/]+)", path)
    if not m:
        raise ValueError(f"Could not extract slug from URL path: {path}")
    return m.group(2).strip()


def normalize_slug_for_search(slug: str) -> str:
    """
    Helps with URLs like:
    us-strike-on-somalia-by-january-31-338
    where canonical Gamma slug may not contain the trailing numeric suffix.
    """
    return re.sub(r"-\d+$", "", slug.strip())


# ----------------------------
# Gamma: canonical fetch + public-search fallback
# ----------------------------
def gamma_get_market_by_slug(slug: str) -> dict:
    url = f"{GAMMA_BASE}/markets/slug/{slug}"
    r = session.get(url, timeout=30)
    r.raise_for_status()
    return r.json()


def gamma_public_search(query: str, limit_per_type: int = 50, page: int = 1) -> dict:
    """
    Correct Gamma public search endpoint: GET /public-search
    """
    url = f"{GAMMA_BASE}/public-search"
    params = {"q": query, "limit_per_type": limit_per_type, "page": page}
    r = session.get(url, params=params, timeout=30)
    r.raise_for_status()
    return r.json()


def gamma_get_market_by_slug_or_search(slug: str) -> dict:
    """
    1) Try exact /markets/slug/{slug}
    2) Try normalized slug without trailing numeric suffix
    3) Fallback to /public-search
    """
    tried = []

    # Exact slug
    try:
        tried.append(slug)
        return gamma_get_market_by_slug(slug)
    except requests.HTTPError as e:
        resp = getattr(e, "response", None)
        if resp is None or resp.status_code != 404:
            raise

    # Normalized slug
    normalized = normalize_slug_for_search(slug)
    if normalized != slug:
        try:
            tried.append(normalized)
            return gamma_get_market_by_slug(normalized)
        except requests.HTTPError as e:
            resp = getattr(e, "response", None)
            if resp is None or resp.status_code != 404:
                raise

    # Public search fallback
    q = normalized.replace("-", " ")
    sr = gamma_public_search(q, limit_per_type=50, page=1)

    candidates = []
    events = sr.get("events", []) if isinstance(sr, dict) else []
    for ev in events:
        mkts = ev.get("markets", [])
        if isinstance(mkts, list):
            candidates.extend(mkts)

    if not candidates:
        raise RuntimeError(
            f"No market candidates found in public-search for query='{q}' "
            f"(original slug='{slug}', tried={tried})."
        )

    # exact match against original or normalized
    exact = [
        m for m in candidates
        if str(m.get("slug", "")) in {slug, normalized}
    ]
    if exact:
        chosen_slug = str(exact[0]["slug"])
        return gamma_get_market_by_slug(chosen_slug)

    def score(m):
        s = str(m.get("slug", ""))
        overlap = sum(1 for token in normalized.split("-") if token in s)
        exact_prefix = 1 if s.startswith(normalized[:20]) else 0
        return (exact_prefix, overlap, -abs(len(s) - len(normalized)))

    chosen = sorted(candidates, key=score, reverse=True)[0]
    chosen_slug = chosen.get("slug")
    if not chosen_slug:
        raise RuntimeError(f"Chosen candidate missing slug. Keys: {list(chosen.keys())}")

    return gamma_get_market_by_slug(str(chosen_slug))


def _maybe_parse_json_list(x):
    if isinstance(x, list):
        return x
    if isinstance(x, str):
        s = x.strip()
        if s.startswith("[") and s.endswith("]"):
            return json.loads(s)
    return x


def extract_yes_no_token_ids(market: dict) -> tuple[str, str]:
    outcomes = _maybe_parse_json_list(market.get("outcomes"))
    clob_ids = _maybe_parse_json_list(market.get("clobTokenIds"))

    if not (isinstance(outcomes, list) and isinstance(clob_ids, list) and len(outcomes) == len(clob_ids)):
        raise ValueError(
            f"Unexpected shapes. outcomes={type(outcomes)} clobTokenIds={type(clob_ids)} "
            f"len(outcomes)={len(outcomes) if isinstance(outcomes, list) else 'NA'} "
            f"len(clob_ids)={len(clob_ids) if isinstance(clob_ids, list) else 'NA'}"
        )

    yes_id = None
    no_id = None

    for o, tid in zip(outcomes, clob_ids):
        o_norm = str(o).strip().lower()
        if o_norm == "yes":
            yes_id = str(tid)
        elif o_norm == "no":
            no_id = str(tid)

    if not yes_id or not no_id:
        raise ValueError(f"Could not locate YES/NO in outcomes: {outcomes}")

    return yes_id, no_id


# ----------------------------
# Goldsky Orderbook Subgraph
# ----------------------------
def gql_post(query: str, variables: dict | None = None) -> dict:
    r = session.post(
        ORDERBOOK_ENDPOINT,
        json={"query": query, "variables": variables or {}},
        timeout=60
    )
    r.raise_for_status()
    out = r.json()
    if "errors" in out:
        raise RuntimeError(out["errors"])
    return out["data"]


def fetch_fills_for_asset(asset_id: str, days_back: int = 365, page_size: int = 1000) -> pd.DataFrame:
    end_ts = int(time.time())
    start_ts = end_ts - days_back * 24 * 60 * 60

    q = """
    query($first: Int!, $ts_gt: BigInt!, $ts_lte: BigInt!, $asset: String!) {
      orderFilledEvents(
        first: $first
        orderBy: timestamp
        orderDirection: asc
        where: {
          or: [
            { makerAssetId: $asset, timestamp_gt: $ts_gt, timestamp_lte: $ts_lte }
            { takerAssetId: $asset, timestamp_gt: $ts_gt, timestamp_lte: $ts_lte }
          ]
        }
      ) {
        id
        transactionHash
        timestamp
        maker
        taker
        makerAssetId
        takerAssetId
        makerAmountFilled
        takerAmountFilled
        fee
      }
    }
    """

    rows = []
    ts_cursor = start_ts
    pages = 0

    while True:
        vars_ = {
            "first": page_size,
            "ts_gt": str(ts_cursor),
            "ts_lte": str(end_ts),
            "asset": asset_id
        }
        data = gql_post(q, vars_)
        batch = data.get("orderFilledEvents", [])
        if not batch:
            break

        rows.extend(batch)
        pages += 1

        # Advance cursor carefully
        last_ts = int(batch[-1]["timestamp"])
        if last_ts <= ts_cursor:
            ts_cursor += 1
        else:
            ts_cursor = last_ts

        if pages % 10 == 0:
            print(f"  fetched pages={pages}, rows={len(rows)}")

        if len(batch) < page_size:
            break

    df = pd.DataFrame(rows)
    if df.empty:
        return df

    df["timestamp"] = df["timestamp"].astype(int)
    df["datetime_utc"] = pd.to_datetime(df["timestamp"], unit="s", utc=True)
    df["makerAmountFilled"] = pd.to_numeric(df["makerAmountFilled"], errors="coerce")
    df["takerAmountFilled"] = pd.to_numeric(df["takerAmountFilled"], errors="coerce")

    # Deduplicate both by event id and transaction hash where available
    subset_cols = [c for c in ["id", "transactionHash"] if c in df.columns]
    df = df.drop_duplicates(subset=subset_cols)

    return df.sort_values("timestamp").reset_index(drop=True)


def compute_trade_price_for_asset(fills: pd.DataFrame, asset_id: str) -> pd.DataFrame:
    if fills.empty:
        return fills.copy()

    df = fills.copy()

    is_maker = df["makerAssetId"] == asset_id
    is_taker = df["takerAssetId"] == asset_id

    df["raw_price"] = np.nan
    df.loc[is_maker, "raw_price"] = (
        df.loc[is_maker, "takerAmountFilled"] / df.loc[is_maker, "makerAmountFilled"]
    )
    df.loc[is_taker, "raw_price"] = (
        df.loc[is_taker, "makerAmountFilled"] / df.loc[is_taker, "takerAmountFilled"]
    )

    df["raw_price"] = df["raw_price"].replace([np.inf, -np.inf], np.nan)

    # Inversion guard for fills recorded in opposite ratio orientation
    df["price"] = df["raw_price"]
    mask_gt1 = df["price"] > 1
    df.loc[mask_gt1, "price"] = 1 / df.loc[mask_gt1, "price"]

    # Keep only plausible probabilities
    df.loc[(df["price"] <= 0) | (df["price"] > 1), "price"] = np.nan

    return df.dropna(subset=["price"]).reset_index(drop=True)


def build_daily_series(priced_fills: pd.DataFrame) -> pd.DataFrame:
    if priced_fills.empty:
        return priced_fills.copy()

    tmp = priced_fills.set_index("datetime_utc").sort_index()

    daily = pd.DataFrame()
    daily["p_yes_close"] = tmp["price"].resample("1D").last()

    vol_proxy_trade = tmp[["makerAmountFilled", "takerAmountFilled"]].min(axis=1)
    daily["volproxy_yes"] = vol_proxy_trade.resample("1D").sum(min_count=1)

    daily["ret_yes"] = np.log(daily["p_yes_close"] / daily["p_yes_close"].shift(1))
    daily["vol7_yes"] = daily["ret_yes"].rolling(7).std()

    daily = daily.dropna(subset=["p_yes_close"]).reset_index()
    return daily.rename(columns={"datetime_utc": "date"})


# ----------------------------
# Plot (Polymarket-style)
# ----------------------------
def plot_polymarket_style(df_daily_yes: pd.DataFrame, slug: str):
    if df_daily_yes.empty:
        print(f"⚠️ No data to plot for {slug}")
        return None

    df = df_daily_yes.sort_values("date").copy()
    x = df["date"]
    y = df["p_yes_close"]

    last_p = y.iloc[-1]
    ymax = float(y.max()) if len(y) else 0.5
    upper = min(1.0, max(0.55, ymax * 1.10))

    fig, ax = plt.subplots(figsize=(12, 5))
    pm_blue = "#2F6BFF"

    ax.plot(x, y, color=pm_blue, linewidth=2.5)
    ax.scatter([x.iloc[-1]], [last_p], color=pm_blue, s=90, zorder=3)

    ax.text(
        0.01, 0.90, f"{last_p:.0%} chance",
        transform=ax.transAxes,
        fontsize=28,
        fontweight="bold",
        ha="left",
        va="top"
    )

    ax.yaxis.set_major_formatter(PercentFormatter(1.0))
    ax.set_ylim(0, upper)

    ax.xaxis.set_major_locator(mdates.MonthLocator())
    ax.xaxis.set_major_formatter(mdates.DateFormatter("%b"))

    ax.grid(True, axis="y", linestyle="--", linewidth=0.8, alpha=0.3)
    ax.grid(False, axis="x")
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
    ax.yaxis.tick_right()
    ax.yaxis.set_label_position("right")

    ax.set_xlabel("")
    ax.set_ylabel("")
    ax.set_title(slug, loc="left", fontsize=11, alpha=0.7)

    plt.tight_layout()
    out = f"chart_{slug}.png"
    plt.savefig(out, dpi=200, bbox_inches="tight")
    plt.close(fig)

    print(f"✅ Chart saved: {out}")
    return out


# ----------------------------
# One market builder
# ----------------------------
def build_market(polymarket_url: str, days_back: int = 365) -> tuple[pd.DataFrame, dict]:
    original_slug = extract_slug(polymarket_url)
    print(f"\n=== Processing URL ===")
    print(polymarket_url)
    print(f"Extracted slug: {original_slug}")

    market = gamma_get_market_by_slug_or_search(original_slug)
    canonical_slug = str(market.get("slug", original_slug))
    yes_id, no_id = extract_yes_no_token_ids(market)

    print("Canonical slug:", canonical_slug)
    print("YES id:", yes_id)
    print("NO  id:", no_id)

    print("Downloading YES fills...")
    yes_fills = fetch_fills_for_asset(yes_id, days_back=days_back)
    print("YES fills:", len(yes_fills))

    print("Downloading NO fills...")
    no_fills = fetch_fills_for_asset(no_id, days_back=days_back)
    print("NO fills:", len(no_fills))

    yes_fills.to_csv(f"fills_yes_raw_{canonical_slug}.csv", index=False)
    no_fills.to_csv(f"fills_no_raw_{canonical_slug}.csv", index=False)

    yes_priced = compute_trade_price_for_asset(yes_fills, yes_id)
    no_priced = compute_trade_price_for_asset(no_fills, no_id)

    print("YES priced rows:", len(yes_priced))
    print("NO  priced rows:", len(no_priced))

    yes_daily = build_daily_series(yes_priced)
    yes_daily["slug"] = canonical_slug

    no_daily = build_daily_series(no_priced).rename(columns={"p_yes_close": "p_no_close"})

    final = pd.merge(
        yes_daily,
        no_daily[["date", "p_no_close"]],
        on="date",
        how="left"
    ).sort_values("date")

    final["no_implied_yes"] = 1 - final["p_no_close"]
    final["spread_yes_vs_implied"] = final["p_yes_close"] - final["no_implied_yes"]

    # Save market-level outputs
    yes_daily.to_csv(f"polymarket_daily_yes_{canonical_slug}.csv", index=False)
    final.to_csv(f"polymarket_daily_final_{canonical_slug}.csv", index=False)

    chart_path = plot_polymarket_style(yes_daily, canonical_slug)

    summary = {
        "input_slug": original_slug,
        "canonical_slug": canonical_slug,
        "yes_id": yes_id,
        "no_id": no_id,
        "rows_yes_fills": int(len(yes_fills)),
        "rows_no_fills": int(len(no_fills)),
        "rows_yes_priced": int(len(yes_priced)),
        "rows_no_priced": int(len(no_priced)),
        "rows_daily_final": int(len(final)),
        "date_min": str(final["date"].min()) if len(final) else None,
        "date_max": str(final["date"].max()) if len(final) else None,
        "p_yes_mean": float(final["p_yes_close"].mean(skipna=True)) if len(final) else np.nan,
        "ret_yes_std": float(final["ret_yes"].std(skipna=True)) if len(final) else np.nan,
        "spread_abs_mean": float(final["spread_yes_vs_implied"].abs().mean(skipna=True)) if len(final) else np.nan,
        "chart_png": chart_path,
        "status": "ok"
    }

    print("Daily rows:", summary["rows_daily_final"])
    print("Range:", summary["date_min"], "->", summary["date_max"])
    print("Mean price:", summary["p_yes_mean"])
    print("Return std:", summary["ret_yes_std"])
    print("Spread abs mean:", summary["spread_abs_mean"])

    return final, summary


# ----------------------------
# Batch runner
# ----------------------------
def run_batch(urls: list[str], days_back: int = 365):
    panel_parts = []
    summaries = []
    failures = []

    for u in urls:
        try:
            market_df, summary = build_market(u, days_back=days_back)
            panel_parts.append(market_df)
            summaries.append(summary)
        except Exception as e:
            failed_slug = None
            try:
                failed_slug = extract_slug(u)
            except Exception:
                failed_slug = "unknown"

            failures.append(
                {
                    "url": u,
                    "slug": failed_slug,
                    "error_type": type(e).__name__,
                    "error_message": str(e)
                }
            )
            print(f"\n❌ Failed for URL: {u}")
            print(f"   {type(e).__name__}: {e}")

    # Save full panel
    if panel_parts:
        panel = pd.concat(panel_parts, ignore_index=True).sort_values(["slug", "date"])
        panel.to_csv("polymarket_panel_daily.csv", index=False)

        print("\n✅ Saved panel dataset: polymarket_panel_daily.csv")
        print("Panel rows:", len(panel))
        print("Markets in panel:", panel["slug"].nunique())
        print("Market slugs in panel:", sorted(panel["slug"].dropna().unique().tolist()))
    else:
        panel = pd.DataFrame()
        print("\n⚠️ No panel created.")

    # Save summary
    if summaries:
        summary_df = pd.DataFrame(summaries)
        summary_df.to_csv("polymarket_batch_summary.csv", index=False)
        print("✅ Saved summary: polymarket_batch_summary.csv")
    else:
        summary_df = pd.DataFrame()

    # Save failures
    if failures:
        failures_df = pd.DataFrame(failures)
        failures_df.to_csv("polymarket_batch_failures.csv", index=False)
        print("⚠️ Saved failures: polymarket_batch_failures.csv")
    else:
        failures_df = pd.DataFrame()

    # Final diagnostics
    print("\n================ FINAL DIAGNOSTICS ================")
    print(f"Requested URLs: {len(urls)}")
    print(f"Successful markets: {len(summaries)}")
    print(f"Failed markets: {len(failures)}")

    if len(summaries) > 0:
        charts = [s.get("chart_png") for s in summaries if s.get("chart_png")]
        print(f"Charts generated: {len(charts)}")
        print("Charts:", charts)

    if len(failures) > 0:
        print("\nFailed URLs detail:")
        for f in failures:
            print(f"- {f['slug']}: {f['error_type']} -> {f['error_message']}")

    return panel, summary_df, failures_df


