# ----------------------------
def gnews_fetch_day_single(query: str, day: pd.Timestamp) -> list[dict]:
    day_utc = pd.Timestamp(day).tz_localize("UTC") if day.tzinfo is None else day.tz_convert("UTC")
    params = {
        "q":      query,
        "from":   day_utc.strftime("%Y-%m-%dT00:00:00Z"),
        "to":     day_utc.strftime("%Y-%m-%dT23:59:59Z"),
        "max":    100,
        "apikey": GNEWS_API_KEY,
    }

    for attempt in range(5):
        try:
            resp = gnews_session.get(GNEWS_ENDPOINT, params=params, timeout=30)

            if resp.status_code == 429:
                wait = 30 * (attempt + 1)
                print(f"  [429] Rate limit. Esperando {wait}s...")
                time.sleep(wait)
                continue

            if resp.status_code != 200:
                raise RuntimeError(f"HTTP {resp.status_code}: {resp.text[:300]}")

            return resp.json().get("articles", [])

        except Exception as e:
            wait = max(2, min(30, 2 ** attempt))
            print(f"  [Retry {attempt+1}/5] {e} — esperando {wait}s")
            time.sleep(wait)

    print(f"  [FAILED] {day.date()} query='{query}'")
    return []


# ----------------------------
# Fetch todas las queries de un slug para un día + deduplicar
# ----------------------------
def gnews_fetch_day_multi(queries: list[str], day: pd.Timestamp) -> int:
    """
    Lanza todas las queries del slug para un día,
    deduplica por URL y devuelve el conteo real único.
    """
    seen_urls = set()
    total_unique = 0

    for query in queries:
        articles = gnews_fetch_day_single(query, day)
        time.sleep(REQUEST_SPACING_SECONDS)

        for art in articles:
            url = art.get("url", "")
            if url and url not in seen_urls:
                seen_urls.add(url)
                total_unique += 1

    return total_unique


# ----------------------------
# Procesar un (slug, day)
# ----------------------------
def process_day(slug: str, queries: list[str], day: pd.Timestamp) -> dict:
    count = gnews_fetch_day_multi(queries, day)
    print(f"  [{slug[:35]}] {day.date()} → {count} artículos únicos")
    return {"date": day, "slug": slug, "news_count": count}


# ----------------------------
# Pipeline por slug
# ----------------------------
def build_counts_for_slug(panel: pd.DataFrame, slug: str, queries: list[str]) -> pd.DataFrame:
    sub = panel[panel["slug"] == slug].copy()
    if sub.empty:
        return pd.DataFrame()

    sub["date"] = pd.to_datetime(sub["date"], utc=True).dt.floor("D")
    market_days = sorted(sub["date"].unique())

    results = []
    with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
        futures = {
            executor.submit(process_day, slug, queries, day): day
            for day in market_days
        }
        for future in as_completed(futures):
            try:
                results.append(future.result())
            except Exception as e:
                print(f"  [ERROR] {futures[future].date()}: {e}")

    return pd.DataFrame(results).sort_values("date").reset_index(drop=True) if results else pd.DataFrame()


# ----------------------------
# Main
# ----------------------------
def build_gnews_count_panel(
    panel_csv="polymarket_panel_daily.csv",
    out_csv="gnews_counts_daily.csv"
):
    panel = pd.read_csv(panel_csv, parse_dates=["date"])
    panel["date"] = pd.to_datetime(panel["date"], utc=True).dt.floor("D")

    parts = []
    failed_slugs = []

    for slug in sorted(panel["slug"].unique()):
        if slug not in KEYWORDS:
            print(f"Skipping: {slug}")
            continue

        queries = KEYWORDS[slug]
        print(f"\n[GNews] {slug} ({len(queries)} queries)")

        try:
            df = build_counts_for_slug(panel, slug, queries)
            if not df.empty:
                df.to_csv(f"gnews_counts_{slug}.csv", index=False)
                parts.append(df)
        except Exception as e:
            print(f"[FAILED] {slug}: {e}")
            failed_slugs.append(slug)

    counts_df = (
        pd.concat(parts, ignore_index=True)
        if parts
        else pd.DataFrame(columns=["date", "slug", "news_count"])
    )
    counts_df.to_csv(out_csv, index=False)
    print(f"\nGuardado: {out_csv}")

    if failed_slugs:
        print("\nFailed slugs:")
        for s in failed_slugs:
            print(f" - {s}")

# --- RUN ---
build_gnews_count_panel()

