"""# 5. Sentiment Analysis

Sentiment of news coverage related to each prediction market slug, aggregated at daily frequency.
"""

import pandas as pd
import requests
import time
from concurrent.futures import ThreadPoolExecutor, as_completed
from transformers import pipeline
import torch

# ----------------------------
# Config
# ----------------------------
GNEWS_API_KEY = "2a9ce3bbb136e6a5836de4211ecab918"
GNEWS_ENDPOINT = "https://gnews.io/api/v4/search"
MAX_WORKERS = 5
REQUEST_SPACING_SECONDS = 0.2

KEYWORDS = {
    "israel-strikes-iran-by-february-28-2026": [
        "Israel Iran",
        "IDF Iran",
        "Israeli forces Iran",
        "Iran missile attack",
        "Tehran strike",
        "IRGC attack",
        "Israel airstrike",
    ],

    "russia-x-ukraine-ceasefire-by-january-31-2026": [
        "Ukraine ceasefire",
        "Ukraine peace talks",
        "Russia Ukraine truce",
        "Ukraine armistice",
    ],

    "trump-x-greenland-deal-signed-by-january-31": [
        "Greenland Trump",
        "Greenland Denmark deal",
        "Greenland acquisition",
    ],

    "us-strike-on-somalia-by-january-31": [
        "Somalia airstrike",
        "Somalia bombing",
        "Somalia AFRICOM",
        "US military Somalia",
        "Somalia attack",
        "Somalia drone",
        "Somalia Pentagon",
        "Somalia strike",
        "Somalia operation",
        "Somalia counterterrorism",
        "Somalia Shabaab attack",
        "Somalia US operation",
        "Somalia air strike",
        "Somalia killed",
    ],

    "us-x-iran-nuclear-talks-resume-by-march-31": [
        "Iran nuclear deal",
        "Iran nuclear talks",
        "JCPOA negotiations",
        "Iran US diplomacy",
    ],
}

# ----------------------------
# Cargar FinBERT una sola vez
# ----------------------------
print("Cargando FinBERT...")
device = 0 if torch.cuda.is_available() else -1
sentiment_pipeline = pipeline(
    "text-classification",
    model="ProsusAI/finbert",
    tokenizer="ProsusAI/finbert",
    device=device,
    truncation=True,
    max_length=512,
    top_k=None
)
print(f"FinBERT cargado en {'GPU' if device == 0 else 'CPU'}")

LABEL_TO_SCORE = {"positive": 1.0, "neutral": 0.0, "negative": -1.0}

def score_from_finbert(text: str) -> float:
    if not text or not text.strip():
        return 0.0
    results = sentiment_pipeline(text[:512])[0]
    return round(sum(LABEL_TO_SCORE.get(r["label"].lower(), 0.0) * r["score"] for r in results), 4)

# ----------------------------
# GNews: fetch artículos de un día para UNA query (solo inglés)
# ----------------------------
gnews_session = requests.Session()
gnews_session.headers.update({
    "User-Agent": "TFG-GNews-Sentiment/2.0",
    "Accept": "application/json"
})

def gnews_fetch_day_single(query: str, day: pd.Timestamp) -> list[dict]:
    day_utc = pd.Timestamp(day).tz_localize("UTC") if day.tzinfo is None else day.tz_convert("UTC")
    params = {
        "q":      query,
        "lang":   "en",
        "from":   day_utc.strftime("%Y-%m-%dT00:00:00Z"),
        "to":     day_utc.strftime("%Y-%m-%dT23:59:59Z"),
        "max":    100,
        "apikey": GNEWS_API_KEY,
    }

    for attempt in range(5):
        try:
            resp = gnews_session.get(GNEWS_ENDPOINT, params=params, timeout=30)
            if resp.status_code == 429:
                wait = 30 * (attempt + 1)
                print(f"  [429] Esperando {wait}s...")
                time.sleep(wait)
                continue
            if resp.status_code != 200:
                raise RuntimeError(f"HTTP {resp.status_code}: {resp.text[:300]}")
            return resp.json().get("articles", [])
        except Exception as e:
            wait = max(2, min(30, 2 ** attempt))
            print(f"  [Retry {attempt+1}/5] {e} — esperando {wait}s")
            time.sleep(wait)

    print(f"  [FAILED] {day.date()} query='{query}'")
    return []


# ----------------------------
# Fetch todas las queries + deduplicar + analizar sentiment
# ----------------------------
def process_day(slug: str, queries: list[str], day: pd.Timestamp) -> dict:
    seen_urls = set()
    articles_unique = []

    for query in queries:
        articles = gnews_fetch_day_single(query, day)
        time.sleep(REQUEST_SPACING_SECONDS)
        for art in articles:
            url = art.get("url", "")
            if url and url not in seen_urls:
                seen_urls.add(url)
                articles_unique.append(art)

    sentiment_mean = 0.0
    sentiment_std  = 0.0
    positive_ratio = 0.0
    negative_ratio = 0.0

    if articles_unique:
        scores = []
        for art in articles_unique:
            text = " ".join(filter(None, [
                art.get("title", ""),
                art.get("description", "")
            ])).strip()
            scores.append(score_from_finbert(text))

        s = pd.Series(scores)
        sentiment_mean  = round(s.mean(), 4)
        sentiment_std   = round(s.std(ddof=0), 4)
        positive_ratio  = round((s > 0.1).sum() / len(s), 4)
        negative_ratio  = round((s < -0.1).sum() / len(s), 4)

    print(f"  [{slug[:35]}] {day.date()} → n={len(articles_unique)} | sentiment={sentiment_mean:+.3f}")

    return {
        "date":           day,
        "slug":           slug,
        "sentiment_mean": sentiment_mean,
        "sentiment_std":  sentiment_std,
        "positive_ratio": positive_ratio,
        "negative_ratio": negative_ratio,
    }


# ----------------------------
# Pipeline por slug
# ----------------------------
def build_sentiment_for_slug(panel: pd.DataFrame, slug: str, queries: list[str]) -> pd.DataFrame:
    sub = panel[panel["slug"] == slug].copy()
    if sub.empty:
        return pd.DataFrame()

    sub["date"] = pd.to_datetime(sub["date"], utc=True).dt.floor("D")
    market_days = sorted(sub["date"].unique())

    results = []
    with ThreadPoolExecutor(max_workers=MAX_WORKERS) as executor:
        futures = {
            executor.submit(process_day, slug, queries, day): day
            for day in market_days
        }
        for future in as_completed(futures):
            try:
                results.append(future.result())
            except Exception as e:
                print(f"  [ERROR] {futures[future].date()}: {e}")

    return pd.DataFrame(results).sort_values("date").reset_index(drop=True) if results else pd.DataFrame()


# ----------------------------
# Main
# ----------------------------
def build_gnews_sentiment_panel(
    panel_csv="polymarket_panel_daily.csv",
    out_csv="gnews_sentiment_daily.csv"
):
    panel = pd.read_csv(panel_csv, parse_dates=["date"])
    panel["date"] = pd.to_datetime(panel["date"], utc=True).dt.floor("D")

    parts = []
    failed_slugs = []

    for slug in sorted(panel["slug"].unique()):
        if slug not in KEYWORDS:
            print(f"Skipping: {slug}")
            continue

        queries = KEYWORDS[slug]
        print(f"\n[Sentiment] {slug} ({len(queries)} queries)")

        try:
            df = build_sentiment_for_slug(panel, slug, queries)
            if not df.empty:
                df.to_csv(f"gnews_sentiment_{slug}.csv", index=False)
                parts.append(df)
        except Exception as e:
            print(f"[FAILED] {slug}: {e}")
            failed_slugs.append(slug)

    sentiment_df = (
        pd.concat(parts, ignore_index=True)
        if parts
        else pd.DataFrame(columns=["date", "slug", "sentiment_mean",
                                    "sentiment_std", "positive_ratio", "negative_ratio"])
    )
    sentiment_df.to_csv(out_csv, index=False)
    print(f"\nGuardado: {out_csv}")

    if failed_slugs:
        print("\nFailed slugs:")
        for s in failed_slugs:
            print(f" - {s}")

# --- RUN ---
build_gnews_sentiment_panel()

