"""# 6. Merge & Econometric Analysis"""

import pandas as pd

def merge_all(
    panel_csv="polymarket_panel_daily.csv",
    counts_csv="gnews_counts_daily.csv",
    sentiment_csv="gnews_sentiment_daily.csv",
    out_csv="panel_final.csv"
):
    panel     = pd.read_csv(panel_csv,     parse_dates=["date"])
    counts    = pd.read_csv(counts_csv,    parse_dates=["date"])
    sentiment = pd.read_csv(sentiment_csv, parse_dates=["date"])

    for df in [panel, counts, sentiment]:
        df["date"] = pd.to_datetime(df["date"], utc=True).dt.floor("D")

    merged = (
        panel
        .merge(counts,    on=["slug", "date"], how="left")
        .merge(sentiment, on=["slug", "date"], how="left")
    )

    merged["news_count"]     = merged["news_count"].fillna(0).astype(int)
    merged["sentiment_mean"] = merged["sentiment_mean"].fillna(0.0)
    merged["sentiment_std"]  = merged["sentiment_std"].fillna(0.0)
    merged["positive_ratio"] = merged["positive_ratio"].fillna(0.0)
    merged["negative_ratio"] = merged["negative_ratio"].fillna(0.0)

    merged.to_csv(out_csv, index=False)
    print(f"Guardado: {out_csv} ({len(merged)} filas, {merged['slug'].nunique()} slugs)")
    print(merged.groupby("slug")[["news_count", "sentiment_mean"]].describe().round(3))

merge_all()

