import pandas as pd
import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec
import matplotlib.patches as mpatches
import matplotlib.lines as mlines

def plot_slug(fig, outer_spec, df_slug, slug):
    df = df_slug.sort_values("date").copy()
    dates = df["date"]

    nc = df["news_count"]
    nc_norm = (nc - nc.min()) / (nc.max() - nc.min() + 1e-9)

    inner = gridspec.GridSpecFromSubplotSpec(
        2, 1, subplot_spec=outer_spec, hspace=0.05, height_ratios=[2, 1]
    )
    ax1 = fig.add_subplot(inner[0])
    ax3 = fig.add_subplot(inner[1], sharex=ax1)

    # --- Probabilidad de mercado ---
    ax1.plot(dates, df["p_yes_close"], color="#2563eb", linewidth=1.8)
    ax1.set_ylabel("Implied Prob", color="#2563eb", fontsize=8)
    ax1.tick_params(axis="y", labelcolor="#2563eb")
    ax1.set_ylim(-0.05, 1.05)
    ax1.set_title(slug.replace("-", " "), fontsize=8, fontweight="bold", pad=4)
    ax1.tick_params(axis="x", labelbottom=False)

    # --- News count normalizado (eje derecho) ---
    ax2 = ax1.twinx()
    ax2.bar(dates, nc_norm, color="#f59e0b", alpha=0.35, width=0.8)
    ax2.set_ylabel("News (norm)", color="#f59e0b", fontsize=7)
    ax2.tick_params(axis="y", labelcolor="#f59e0b")
    ax2.set_ylim(0, 3)

    # --- Sentiment ---
    ax3.plot(dates, df["sentiment_mean"], color="#10b981", linewidth=1.2)
    ax3.axhline(0, color="gray", linewidth=0.5, linestyle="--")
    ax3.fill_between(dates, df["sentiment_mean"], 0,
                     where=df["sentiment_mean"] >= 0, alpha=0.25, color="#10b981")
    ax3.fill_between(dates, df["sentiment_mean"], 0,
                     where=df["sentiment_mean"] < 0, alpha=0.25, color="#ef4444")
    ax3.set_ylabel("Sentiment", color="#10b981", fontsize=8)
    ax3.tick_params(axis="y", labelcolor="#10b981")
    ax3.set_ylim(-1.1, 1.1)
    ax3.tick_params(axis="x", labelsize=6, rotation=30)

    # Leyenda
    legend_handles = [
        mlines.Line2D([0], [0], color="#2563eb", linewidth=1.8, label="Market prob (p_yes)"),
        mpatches.Patch(color="#f59e0b", alpha=0.5, label="News count (norm)"),
        mlines.Line2D([0], [0], color="#10b981", linewidth=1.2, label="Sentiment mean"),
    ]
    ax1.legend(handles=legend_handles, loc="upper left", fontsize=7, framealpha=0.7)


def plot_all(panel_csv="panel_final.csv", out_png="panel_visualization.png"):
    df = pd.read_csv(panel_csv, parse_dates=["date"])
    df["date"] = pd.to_datetime(df["date"], utc=True).dt.floor("D")

    slugs = sorted(df["slug"].unique())
    n = len(slugs)

    fig = plt.figure(figsize=(18, n * 4.5))
    outer = gridspec.GridSpec(n, 1, figure=fig, hspace=0.7)

    for i, slug in enumerate(slugs):
        df_slug = df[df["slug"] == slug].copy()
        plot_slug(fig, outer[i], df_slug, slug)

    fig.suptitle(
        "Polymarket: Market Probability vs News Volume vs Sentiment",
        fontsize=13, fontweight="bold", y=1.01
    )

    plt.savefig(out_png, dpi=150, bbox_inches="tight")
    print(f"Guardado: {out_png}")
    plt.show()


plot_all()

import pandas as pd
import numpy as np
import statsmodels.api as sm

# ----------------------------
# Cargar y preparar
# ----------------------------
df = pd.read_csv("panel_final.csv", parse_dates=["date"])
df["date"] = pd.to_datetime(df["date"], utc=True).dt.floor("D")
df = df.sort_values(["slug", "date"]).reset_index(drop=True)

# ----------------------------
# Feature engineering por slug
# ----------------------------
def add_features(g):
    g = g.copy()

    # Lags de news y sentiment
    g["log_news"]       = np.log1p(g["news_count"])
    g["log_news_lag1"]  = g["log_news"].shift(1)
    g["sentiment_lag1"] = g["sentiment_mean"].shift(1)
    g["pos_ratio_lag1"] = g["positive_ratio"].shift(1)
    g["neg_ratio_lag1"] = g["negative_ratio"].shift(1)

    # News spike: z-score del log_news
    mu  = g["log_news"].mean()
    std = g["log_news"].std() + 1e-9
    g["news_zscore_lag1"] = ((g["log_news"] - mu) / std).shift(1)

    return g

df = df.groupby("slug", group_keys=False).apply(add_features)

# ----------------------------
# OLS por slug + pooled
# ----------------------------
FEATURES = ["sentiment_lag1", "log_news_lag1", "news_zscore_lag1",
            "pos_ratio_lag1", "neg_ratio_lag1"]

def run_ols(data, label):
    sub = data.dropna(subset=["ret_yes"] + FEATURES)
    if len(sub) < 10:
        print(f"\n[{label}] — insuficientes observaciones ({len(sub)}), skip")
        return None

    X = sm.add_constant(sub[FEATURES])
    y = sub["ret_yes"]
    model = sm.OLS(y, X).fit(cov_type="HC1")

    print(f"\n{'='*60}")
    print(f"OLS — {label}  (n={len(sub)})")
    print(f"{'='*60}")
    print(model.summary2().tables[1].to_string())
    print(f"R²={model.rsquared:.4f}  |  Adj R²={model.rsquared_adj:.4f}  |  F-pval={model.f_pvalue:.4f}")
    return model

# Por slug individual
results = {}
for slug in df["slug"].unique():
    results[slug] = run_ols(df[df["slug"] == slug], slug)

# Pooled (todos los slugs juntos)
print("\n" + "="*60)
print("OLS — POOLED (todos los slugs)")
results["pooled"] = run_ols(df, "POOLED")

import pandas as pd
import numpy as np
import statsmodels.api as sm
import matplotlib.pyplot as plt

# ----------------------------
# Cargar y preparar
# ----------------------------
df = pd.read_csv("panel_final.csv", parse_dates=["date"])
df["date"] = pd.to_datetime(df["date"], utc=True).dt.floor("D")
df = df.sort_values(["slug", "date"]).reset_index(drop=True)

# ----------------------------
# Feature engineering por slug
# ----------------------------
def add_features(g):
    g = g.copy()

    # Lags de news y sentiment
    g["log_news"]       = np.log1p(g["news_count"])
    g["log_news_lag1"]  = g["log_news"].shift(1)
    g["sentiment_lag1"] = g["sentiment_mean"].shift(1)
    g["pos_ratio_lag1"] = g["positive_ratio"].shift(1)
    g["neg_ratio_lag1"] = g["negative_ratio"].shift(1)

    # News spike: z-score del log_news
    mu  = g["log_news"].mean()
    std = g["log_news"].std() + 1e-9
    g["news_zscore_lag1"] = ((g["log_news"] - mu) / std).shift(1)

    return g

# Evita el warning de pandas
parts = []
for slug, g in df.groupby("slug"):
    parts.append(add_features(g))
df = pd.concat(parts, ignore_index=True)

# ----------------------------
# OLS por slug + pooled
# ----------------------------
FEATURES = [
    "sentiment_lag1",
    "log_news_lag1",
    "news_zscore_lag1",
    "pos_ratio_lag1",
    "neg_ratio_lag1"
]

results = {}
results_table = []

def run_ols(data, label):
    sub = data.dropna(subset=["ret_yes"] + FEATURES).copy()

    if len(sub) < 10:
        print(f"\n[{label}] — insuficientes observaciones ({len(sub)}), skip")
        return None, None

    X = sm.add_constant(sub[FEATURES])
    y = sub["ret_yes"]
    model = sm.OLS(y, X).fit(cov_type="HC1")

    print(f"\n{'='*60}")
    print(f"OLS — {label}  (n={len(sub)})")
    print(f"{'='*60}")
    print(model.summary2().tables[1].to_string())
    print(f"R²={model.rsquared:.4f}  |  Adj R²={model.rsquared_adj:.4f}  |  F-pval={model.f_pvalue:.4f}")

    table = model.summary2().tables[1].reset_index().rename(columns={"index": "variable"})
    table["slug"] = label
    table["n"] = len(sub)
    table["r2"] = model.rsquared
    table["adj_r2"] = model.rsquared_adj
    table["f_pvalue"] = model.f_pvalue

    # fitted values para plots
    sub = sub.copy()
    sub["fitted"] = model.fittedvalues
    sub["resid"] = model.resid

    return model, (table, sub)

# Por slug individual
for slug in df["slug"].unique():
    model, out = run_ols(df[df["slug"] == slug], slug)
    results[slug] = model
    if out is not None:
        table, sub = out
        results_table.append(table)
        results[f"{slug}_data"] = sub

# Pooled
print("\n" + "="*60)
print("OLS — POOLED (todos los slugs)")
model, out = run_ols(df, "POOLED")
results["POOLED"] = model
if out is not None:
    table, sub = out
    results_table.append(table)
    results["POOLED_data"] = sub

# ----------------------------
# Unificar resultados
# ----------------------------
results_df = pd.concat(results_table, ignore_index=True)

# Renombrar columnas para comodidad
results_df = results_df.rename(columns={
    "Coef.": "coef",
    "Std.Err.": "std_err",
    "z": "z",
    "P>|z|": "pval",
    "[0.025": "ci_low",
    "0.975]": "ci_high"
})

print("\n\n===== RESULTADOS CONSOLIDADOS =====")
print(results_df.head(20).to_string(index=False))

# Guardar si quieres
