"""No hay correlación visual clara
Esto confirma los resultados econométricos
El sentiment no es un predictor robusto
pero puede haber efectos contextuales débiles

The empirical analysis provides no strong or consistent evidence of a linear relationship between lagged news sentiment and short-term changes in prediction market probabilities. Visual inspection of the data reveals no clear correlation, and the regression results confirm that most sentiment-related coefficients are statistically insignificant across markets. However, some weak and context-dependent effects emerge in specific specifications and in the pooled sample, suggesting that sentiment may carry limited predictive information under certain conditions. A key explanation for these findings lies in the mismatch between textual sentiment and event-specific outcomes: positive or negative tone in news coverage does not necessarily correspond to an increase or decrease in the probability of a given geopolitical event. Moreover, in line with semi-strong market efficiency, publicly available information such as news sentiment may be rapidly incorporated into prices, leaving little room for predictive power. Overall, the results indicate that while news sentiment is part of the information environment, its direct impact on belief updating in prediction markets is weak, heterogeneous, and highly dependent on both measurement and context.

*   No clear correlation between sentiment and returns
*   Sentiment is not a robust predictor
*   Some weak, context-dependent effects appear
*   Sentiment ≠ event probability (key limitation)
*   Markets likely incorporate sentiment quickly
*   Results are heterogeneous across markets

future works: toda la noticia
"""

import pandas as pd
import numpy as np
import statsmodels.api as sm

# ----------------------------
# Cargar y preparar
# ----------------------------
df = pd.read_csv("panel_final.csv", parse_dates=["date"])
df["date"] = pd.to_datetime(df["date"], utc=True).dt.floor("D")
df = df.sort_values(["slug", "date"]).reset_index(drop=True)

# ----------------------------
# Feature engineering por slug
# ----------------------------
def add_features(g):
    g = g.copy()

    # Lags de news y sentiment
    g["log_news"]           = np.log1p(g["news_count"])
    g["log_news_lag1"]      = g["log_news"].shift(1)
    g["sentiment_lag1"]     = g["sentiment_mean"].shift(1)
    g["pos_ratio_lag1"]     = g["positive_ratio"].shift(1)
    g["neg_ratio_lag1"]     = g["negative_ratio"].shift(1)
    g["sentiment_std_lag1"] = g["sentiment_std"].shift(1)

    # News spike z-score
    mu  = g["log_news"].mean()
    std = g["log_news"].std() + 1e-9
    g["news_zscore_lag1"] = ((g["log_news"] - mu) / std).shift(1)

    # Controles de mercado
    g["ret_lag1"]      = g["ret_yes"].shift(1)   # momentum / reversión
    g["log_vol_lag1"]  = np.log1p(g["volproxy_yes"]).shift(1)  # volumen de trading
    g["spread_lag1"]   = g["spread_yes_vs_implied"].shift(1)   # ineficiencia de mercado

    # Días hasta deadline (proxy de urgencia)
    g["days_elapsed"] = (g["date"] - g["date"].min()).dt.days

    return g

df = df.groupby("slug", group_keys=False).apply(add_features, include_groups=False)

# ----------------------------
# Fixed effects por slug (dummies)
# ----------------------------
slug_dummies = pd.get_dummies(df["slug"], prefix="slug", drop_first=True)
df = pd.concat([df, slug_dummies], axis=1)
dummy_cols = slug_dummies.columns.tolist()

FEATURES_BASE = [
    "sentiment_lag1",
    "log_news_lag1",
    "news_zscore_lag1",
    "pos_ratio_lag1",
    "neg_ratio_lag1",
    "sentiment_std_lag1",
]

CONTROLS = [
    "ret_lag1",
    "log_vol_lag1",
    "spread_lag1",
    "days_elapsed",
]

# ----------------------------
# Modelos anidados
# ----------------------------
def run_ols(data, features, label):
    sub = data.dropna(subset=["ret_yes"] + features)
    if len(sub) < 10:
        print(f"\n[{label}] — insuficientes observaciones ({len(sub)}), skip")
        return None

    X = sm.add_constant(sub[features])
    y = sub["ret_yes"]
    model = sm.OLS(y, X).fit(cov_type="HC1")

    print(f"\n{'='*65}")
    print(f"OLS — {label}  (n={len(sub)})")
    print(f"{'='*65}")
    print(model.summary2().tables[1].round(4).to_string())
    print(f"R²={model.rsquared:.4f}  |  Adj R²={model.rsquared_adj:.4f}  |  F-pval={model.f_pvalue:.4f}")
    return model

pooled = df.copy()

print("\n>>> MODELO 1: Solo news features (sin controles, sin FE)")
m1 = run_ols(pooled, FEATURES_BASE, "Pooled — solo news features")

print("\n>>> MODELO 2: News features + controles de mercado")
m2 = run_ols(pooled, FEATURES_BASE + CONTROLS, "Pooled — news + controles")

print("\n>>> MODELO 3: News features + controles + fixed effects por slug")
m3 = run_ols(pooled, FEATURES_BASE + CONTROLS + dummy_cols, "Pooled — news + controles + FE")

print("\n>>> MODELO 4: Solo controles de mercado (benchmark)")
m4 = run_ols(pooled, CONTROLS, "Pooled — solo controles (benchmark)")

# ----------------------------
# Tabla comparativa de R²
# ----------------------------
print("\n" + "="*65)
print("TABLA COMPARATIVA")
print("="*65)
rows = [
    ("M1 — solo news",              m1),
    ("M2 — news + controles",       m2),
    ("M3 — news + controles + FE",  m3),
    ("M4 — solo controles (bench)", m4),
]
print(f"{'Modelo':<35} {'R²':>8} {'Adj R²':>8} {'F-pval':>10} {'n':>6}")
print("-"*65)
for label, m in rows:
    if m:
        sub = pooled.dropna(subset=["ret_yes"] + (FEATURES_BASE + CONTROLS + dummy_cols))
        print(f"{label:<35} {m.rsquared:>8.4f} {m.rsquared_adj:>8.4f} {m.f_pvalue:>10.4f} {m.nobs:>6.0f}")